import { monsterData } from './monsterData'

export const nextMonster = () => {
  const nextMonsterIndex = Math.ceil(Math.random() * monsterData.length * 10) %
    monsterData.length
  return { ...monsterData[nextMonsterIndex] }
}

export const generateNewMonster = (state, action) => {
  const monster = nextMonster()
  monster.health = Math.ceil(monster.health + (state.level - 1) * 10.6)
  return {
    ...state,
    monster,
  }
}

export const incrementGold = (state, action) => {
  const gold = state.gold + 1
  return {
    ...state,
    gold,
  }
}

export const incrementLevelKillAmount = (state, action) => {
  const levelKillAmount = state.levelKillAmount + 1
  return {
    ...state,
    levelKillAmount,
  }
}

export const levelUpgrade = (state, action) => {
  if (state.levelKillAmount < state.levelKillAmountRequire) {
    return {
      ...state,
    }
  }

  const levelKillAmount = 0
  const level = state.level + 1
  return {
    ...state,
    level,
    levelKillAmount,
  }
}

export const onMonsterKilled = (state, action) => {
  state = incrementGold(state, action)

  state = incrementLevelKillAmount(state, action)

  state = levelUpgrade(state, action)

  state = generateNewMonster(state, action)

  return {
    ...state,
  }
}

export const damageMonster = (state, action) => {
  const monster = {
    ...state.monster,
    health: state.monster.health - action.data.damage,
  }
  if (monster.health > 0) {
    return {
      ...state,
      monster,
    }
  }

  return onMonsterKilled(state, action)
}

export const upgrade = (state, action) => {
  if (state.gold < state.upgradeCost) {
    return {
      ...state,
    }
  }

  const damage = state.damage + 1
  const gold = state.gold - state.upgradeCost
  const upgradeCost = Math.ceil(state.upgradeCost * 1.46)
  return {
    ...state,
    damage,
    gold,
    upgradeCost,
  }
}
