import React, { useEffect } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { actionCreator } from './redux/actionCreator'

function App () {
  const dispatch = useDispatch()
  const state = useSelector(state => state)

  // event loop
  useEffect(() => {
    const timer = setInterval(() => {
      dispatch(actionCreator.autoAttack())
    }, 1000)
    return () => {
      clearInterval(timer)
    }
  }, [dispatch])

  const handleUpgradeClick = () => {
    dispatch(actionCreator.upgrade())
  }

  const handleAttackClick = () => {
    dispatch(actionCreator.damageMonster(state.damage))
  }

  return (
    <div>
      <h1>Idle Monster</h1>
      <fieldset>
        <p>{`Monster Name: ${state.monster.name}`}</p>
        <p>{`Monster Health: ${state.monster.health}`}</p>
      </fieldset>
      <fieldset>
        <p>{`Level: ${state.level}`}</p>
        <p>{`Level Kill Amount: ${state.levelKillAmount}`}</p>
        <p>{`Level Kill Amount Require: ${state.levelKillAmountRequire}`}</p>
      </fieldset>
      <fieldset>
        <p>{`Gold: ${state.gold}`}</p>
        <p>{`Damage: ${state.damage}`}</p>
        <p>{`Upgrade Cost: ${state.upgradeCost}`}</p>
      </fieldset>
      <button
        onClick={handleUpgradeClick}
        disabled={state.gold < state.upgradeCost}
      >
        Upgrade
      </button>
      <button
        onClick={handleAttackClick}
      >
        Attack
      </button>
    </div>
  )
}

export default App
