import { actionType } from './actionType'
import { actionCreator } from './actionCreator'
import { damageMonster, nextMonster, upgrade } from '../game/gameLogic'

const initState = {
  monster: nextMonster(),
  damage: 1,
  gold: 0,
  level: 1,
  levelKillAmount: 0,
  levelKillAmountRequire: 10,
  upgradeCost: 1,
}

export const reducer = (state = initState, action) => {
  switch (action.type) {
    case actionType.autoAttack: {
      return damageMonster(state, actionCreator.damageMonster(state.damage))
    }
    case actionType.damageMonster: {
      return damageMonster(state, action)
    }
    case actionType.upgrade: {
      return upgrade(state, action)
    }
    default: {
      return state
    }
  }
}
